transform_js:
transformedData = { nodes: [], links: [], categories: [] };

if (rawData && Array.isArray(rawData.rows)) {
  const nodeMap = new Map();
  const categoryIndexMap = new Map();

  function ensureCategory(name) {
    const safeName = String(name || 'Other').trim() || 'Other';
    if (!categoryIndexMap.has(safeName)) {
      categoryIndexMap.set(safeName, categoryIndexMap.size);
    }
    return categoryIndexMap.get(safeName);
  }

  function ensureNode(name, groupName) {
    const safeName = String(name || '').trim();
    if (!safeName) {
      return null;
    }
    const category = ensureCategory(groupName);
    if (!nodeMap.has(safeName)) {
      nodeMap.set(safeName, {
        name: safeName,
        value: 0,
        category
      });
    }
    return nodeMap.get(safeName);
  }

  rawData.rows.forEach((row) => {
    if (!row || typeof row !== 'object') {
      return;
    }
    const source = String(row.source || '').trim();
    const target = String(row.target || '').trim();
    const value = Number(row.value);
    if (!source || !target || !Number.isFinite(value) || value <= 0) {
      return;
    }

    const sourceNode = ensureNode(source, row.source_group);
    const targetNode = ensureNode(target, row.target_group);
    if (!sourceNode || !targetNode) {
      return;
    }

    sourceNode.value += value;
    targetNode.value += value;
    transformedData.links.push({ source, target, value });
  });

  transformedData.nodes = Array.from(nodeMap.values()).map((node) => ({
    ...node,
    symbolSize: Math.min(54, 12 + Math.sqrt(node.value) * 2)
  }));
  transformedData.categories = Array.from(categoryIndexMap.keys()).map((name) => ({ name }));
}

echarts_js:
option = {
  title: {
    text: post.title,
    left: 'center'
  },
  tooltip: {
    trigger: 'item',
    formatter: (params) => {
      if (params.dataType === 'node') {
        return `${params.name}: ${params.data.value}`;
      }
      if (params.dataType === 'edge') {
        return `${params.data.source} -> ${params.data.target}: ${params.data.value}`;
      }
      return '';
    }
  },
  legend: [
    {
      data: (transformedData.categories || []).map((item) => item.name),
      bottom: 0
    }
  ],
  series: [
    {
      type: 'graph',
      layout: 'circular',
      circular: {
        rotateLabel: true
      },
      data: transformedData.nodes || [],
      links: transformedData.links || [],
      categories: transformedData.categories || [],
      roam: true,
      label: {
        show: true,
        position: 'right',
        formatter: '{b}'
      },
      lineStyle: {
        color: 'source',
        opacity: 0.65,
        width: 2,
        curveness: 0.25
      },
      edgeSymbol: ['none', 'arrow'],
      edgeSymbolSize: [4, 10],
      emphasis: {
        focus: 'adjacency',
        lineStyle: {
          width: 4
        }
      }
    }
  ]
};
